import React, { useEffect, useState } from 'react';
import ReactDOM from 'react-dom';
import { AlertCircle, CheckCircle, Info, AlertTriangle, X } from 'lucide-react';
import { AnimatePresence, motion } from 'framer-motion';

export type AlertType = 'success' | 'error' | 'warning' | 'info';

interface AlertModalProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    description: string;
    type?: AlertType;
    onConfirm?: () => void;
    confirmLabel?: string;
    cancelLabel?: string;
}

export const AlertModal: React.FC<AlertModalProps> = ({
    isOpen,
    onClose,
    title,
    description,
    type = 'error',
    onConfirm,
    confirmLabel = 'Confirmar',
    cancelLabel = 'Cancelar'
}) => {
    const [isMounted, setIsMounted] = useState(false);

    useEffect(() => {
        setIsMounted(true);
    }, []);

    if (!isMounted) return null;

    const getIcon = () => {
        switch (type) {
            case 'success': return <CheckCircle size={24} />;
            case 'error': return <AlertTriangle size={24} />; // Using Triangle for error/block context
            case 'warning': return <AlertCircle size={24} />;
            case 'info': return <Info size={24} />;
        }
    };

    const getColorStyles = () => {
        switch (type) {
            case 'success': return { bg: 'bg-emerald-500/10', text: 'text-emerald-500', border: 'border-emerald-500/20', button: 'bg-emerald-500 hover:bg-emerald-600 shadow-[0_0_15px_rgba(16,185,129,0.2)]' };
            case 'error': return { bg: 'bg-red-500/10', text: 'text-red-500', border: 'border-red-500/20', button: 'bg-red-500 hover:bg-red-600 shadow-[0_0_15px_rgba(239,68,68,0.2)]' };
            case 'warning': return { bg: 'bg-amber-500/10', text: 'text-amber-500', border: 'border-amber-500/20', button: 'bg-amber-500 hover:bg-amber-600 shadow-[0_0_15px_rgba(245,158,11,0.2)]' };
            case 'info': return { bg: 'bg-blue-500/10', text: 'text-blue-500', border: 'border-blue-500/20', button: 'bg-blue-500 hover:bg-blue-600 shadow-[0_0_15px_rgba(59,130,246,0.2)]' };
        }
    };

    const styles = getColorStyles();

    return ReactDOM.createPortal(
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-[10001] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in" onClick={onClose}>
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        exit={{ opacity: 0, scale: 0.95 }}
                        transition={{ duration: 0.15 }}
                        className="bg-surface border border-neutral-800 rounded-xl shadow-2xl w-full max-w-sm overflow-hidden flex flex-col transform"
                        onClick={e => e.stopPropagation()}
                    >
                        <div className="p-6 flex flex-col items-center text-center">
                            <div className={`p-3 rounded-full ${styles.bg} ${styles.text} mb-4`}>
                                {getIcon()}
                            </div>

                            <h2 className="text-xl font-bold text-neutral-100 mb-2">{title}</h2>

                            <p className="text-neutral-400 text-sm leading-relaxed mb-6">
                                {description}
                            </p>

                            <div className="flex flex-col gap-2 w-full mt-6">
                                {onConfirm ? (
                                    <>
                                        <button
                                            onClick={onConfirm}
                                            className={`w-full py-2.5 font-bold rounded-lg text-sm text-white transition-all ${styles.button}`}
                                        >
                                            {confirmLabel}
                                        </button>
                                        <button
                                            onClick={onClose}
                                            className="w-full py-2.5 font-bold rounded-lg text-sm text-neutral-500 hover:text-white transition-all uppercase tracking-widest"
                                        >
                                            {cancelLabel}
                                        </button>
                                    </>
                                ) : (
                                    <button
                                        onClick={onClose}
                                        className={`w-full py-2.5 font-bold rounded-lg text-sm text-white transition-all ${styles.button}`}
                                    >
                                        Entendido
                                    </button>
                                )}
                            </div>
                        </div>
                    </motion.div>
                </div>
            )}
        </AnimatePresence>,
        document.body
    );
};

