import React, { useState, useMemo, useEffect } from 'react';
import { NavLink, Outlet } from 'react-router-dom';
import { InfoLayout } from '@/components/layout/InfoLayout';
import { useClients } from '@/context/ClientContext';
import { useContracts } from '@/context/ContractContext';
import { ContractStatus } from '@/types/gcc';
import { Select } from '@/components/ui/Select';
import {
    FileText,
    Activity,
    Smile,
    TrendingUp,
    Calendar,
    HeartPulse,
    User,
    Briefcase,
    Settings,
    Wrench
} from 'lucide-react';

const ACCOUNTS_NAV = [
    { label: 'Resumo Contratual', path: 'contract-summary', icon: FileText },
    { label: 'Stakeholders', path: 'settings', icon: User },
    { label: 'Avaliação de Uso', path: 'usage-evaluation', icon: Activity },
    { label: 'Plano de Acompanhamento', path: 'success-plan', icon: Calendar },
    { label: 'Plano Operacional', path: 'operational-plan', icon: Wrench },
    { label: 'Valor Entregue', path: 'delivered-value', icon: TrendingUp },
    { label: 'Satisfação', path: 'satisfaction', icon: Smile },
    { label: 'Health Score', path: 'health-score', icon: HeartPulse },
];

export const CSMAccountsLayout: React.FC = () => {
    const { clients } = useClients();
    const { allContracts } = useContracts();

    // Local Selection State
    const [selectedClientId, setSelectedClientId] = useState<string>('');
    const [selectedContractId, setSelectedContractId] = useState<string>('');

    // Filtered Contracts based on selected client (Only Vigentes/In Force)
    const filteredContracts = useMemo(() => {
        if (!selectedClientId) return [];
        return allContracts.filter(c =>
            c.clientId === selectedClientId &&
            c.status !== ContractStatus.Finished &&
            c.status !== ContractStatus.Expired
        );
    }, [allContracts, selectedClientId]);

    // Reset selected contract if client changes and current contract no longer belongs to client
    useEffect(() => {
        if (selectedClientId && selectedContractId) {
            const contractExists = filteredContracts.some(c => c.id === selectedContractId);
            if (!contractExists) {
                setSelectedContractId('');
            }
        }
    }, [selectedClientId, filteredContracts, selectedContractId]);

    // Select first contract automatically if only one exists
    useEffect(() => {
        if (filteredContracts.length === 1 && !selectedContractId) {
            setSelectedContractId(filteredContracts[0].id);
        }
    }, [filteredContracts, selectedContractId]);

    // Find selected objects for context sharing
    const selectedClient = useMemo(() => clients.find(c => c.id === selectedClientId), [clients, selectedClientId]);
    const selectedContract = useMemo(() => allContracts.find(c => c.id === selectedContractId), [allContracts, selectedContractId]);

    return (
        <InfoLayout
            title="Gerenciamento de Contas"
            subtitle="Navegação de Sucesso e acompanhamento de clientes."
            rightActions={
                <div className="flex items-center gap-3">
                    {/* Seletores com largura fixa para evitar distorção visual */}
                    <div className="w-56">
                        <Select
                            value={selectedClientId}
                            onChange={(e) => setSelectedClientId(e.target.value)}
                            className="!h-9 !text-[11px] !bg-neutral-900/60 border-primary/20 hover:border-primary/40 focus:border-primary transition-all uppercase font-bold tracking-tight !w-full"
                        >
                            <option value="">Cliente...</option>
                            {clients.map(client => (
                                <option key={client.id} value={client.id}>
                                    {client.fantasyName}
                                </option>
                            ))}
                        </Select>
                    </div>

                    <div className="w-80">
                        <Select
                            value={selectedContractId}
                            onChange={(e) => setSelectedContractId(e.target.value)}
                            disabled={!selectedClientId}
                            className="!h-9 !text-[11px] !bg-neutral-900/60 border-primary/20 hover:border-primary/40 focus:border-primary transition-all disabled:opacity-30 uppercase font-bold tracking-tight !w-full"
                        >
                            <option value="">
                                {!selectedClientId ? 'Aguardando Cliente' : 'Contrato...'}
                            </option>
                            {filteredContracts.map(contract => (
                                <option key={contract.id} value={contract.id}>
                                    {contract.opportunityNumber} - {contract.service}
                                </option>
                            ))}
                        </Select>
                    </div>
                </div>
            }
        >
            <div className="space-y-4">

                {/* Tabs Navigation (Horizontal) */}
                <div className="flex flex-wrap gap-2 border-b border-neutral-800 pb-1">
                    {ACCOUNTS_NAV.map((item) => (
                        <NavLink
                            key={item.path}
                            to={item.path}
                            className={({ isActive }) => `
                flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200
                ${isActive
                                    ? 'bg-primary/10 text-primary ring-1 ring-primary/20'
                                    : 'text-neutral-400 hover:text-neutral-200 hover:bg-white/5'}
                ${!selectedContractId ? 'opacity-50 pointer-events-none grayscale' : ''}
              `}
                        >
                            <item.icon size={16} />
                            {item.label}
                        </NavLink>
                    ))}
                </div>

                {/* Tab Content */}
                <div className="relative min-h-[400px]">
                    {selectedContractId ? (
                        <Outlet context={{ client: selectedClient, contract: selectedContract }} />
                    ) : (
                        <div className="flex flex-col items-center justify-center py-20 text-center space-y-4 bg-white/5 rounded-2xl border border-dashed border-neutral-800">
                            <div className="p-4 bg-primary/10 rounded-full text-primary animate-pulse">
                                <Briefcase size={40} />
                            </div>
                            <div>
                                <h3 className="text-lg font-bold text-neutral-200">Aguardando Seleção de Contexto</h3>
                                <p className="text-sm text-neutral-500 max-w-sm mx-auto mt-1">
                                    Selecione um cliente e um contrato acima para visualizar os dados de sucesso e acompanhamento.
                                </p>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </InfoLayout>
    );
};

