import React, { useState, useEffect, useMemo } from 'react';
import { useOutletContext } from 'react-router-dom';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { ClientContract, Client } from '@/types/gcc';
import { DeliveredValue as DeliveredValueModel, ValueDeliveryType, EstimatedImpact } from '@/types/csm';
import { useDeliveredValue } from '../../hooks/useDeliveredValue';
import { useDeliveredValueCategories } from '../../hooks/useDeliveredValueCategories';
import { useDeliveredValueImpactLevels } from '../../hooks/useDeliveredValueImpactLevels';
import { Button } from '@/components/ui/Button';
import { Modal } from '@/components/ui/Modal';
import { Input } from '@/components/ui/Input';
import { Select } from '@/components/ui/Select';
import {
    Plus,
    Trophy,
    Target,
    ShieldCheck,
    TrendingUp,
    FileCheck,
    DollarSign,
    Users,
    Calendar,
    Briefcase,
    Zap,
    AlertCircle,
    MessageCircle,
    Trash2,
    Pencil
} from 'lucide-react';
import { DeleteConfirmationModal } from '@/components/ui/DeleteConfirmationModal';
import { useAuth } from '@/context/AuthContext';
import { useUsersQuery } from '@/hooks/queries/useUsersQuery';
import { useResources } from '@/context/ResourceContext';

interface OutletContextType {
    client: Client;
    contract: ClientContract;
}

// O valueTypeLabels e impactColors agora serão carregados dinamicamente do banco de dados

export const DeliveredValue: React.FC = () => {
    const { contract } = useOutletContext<OutletContextType>();
    const { currentUser } = useAuth();
    const { evaluations, isLoading: loadingEvaluations, fetchDeliveredValues, addDeliveredValue, updateDeliveredValue, deleteDeliveredValue } = useDeliveredValue(contract?.id);
    const { categories, loading: loadingCategories } = useDeliveredValueCategories(contract?.tenantId);
    const { impactLevels, loading: loadingImpact } = useDeliveredValueImpactLevels(contract?.tenantId);
    const { data: profiles = [], isLoading: loadingProfiles } = useUsersQuery();
    const { manufacturers, isLoadingManufacturers } = useResources();
    const isLoading = loadingEvaluations || loadingProfiles || isLoadingManufacturers || loadingCategories || loadingImpact;

    // Criar um mapeamento dinâmico de ID/Key para Nome
    const categoryLabels = useMemo(() => {
        const labels: Record<string, string> = {};
        categories.forEach(cat => {
            labels[cat.key_identifier] = cat.name;
        });
        return labels;
    }, [categories]);

    // Dinâmico: Cores e Labels de Impacto
    const impactColorMap = useMemo(() => {
        const colors: Record<string, string> = {};
        impactLevels.forEach(il => {
            colors[il.key_identifier] = il.color_class;
        });
        return colors;
    }, [impactLevels]);

    const impactLabels = useMemo(() => {
        const labels: Record<string, string> = {};
        impactLevels.forEach(il => {
            labels[il.key_identifier] = il.name;
        });
        return labels;
    }, [impactLevels]);

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
    const [itemToDelete, setItemToDelete] = useState<DeliveredValueModel | null>(null);
    const [itemToEdit, setItemToEdit] = useState<DeliveredValueModel | null>(null);

    // Form state
    const [formData, setFormData] = useState({
        delivery_date: format(new Date(), 'yyyy-MM-dd'),
        manufacturer_name: contract?.manufacturer || '',
        value_type: '', // Inicializado vazio até as categorias carregarem
        description: '',
        impacted_area: 'TI / Tecnologia', // Novo campo obrigatório
        internal_responsible_id: currentUser?.id || '',
        estimated_impact: 'MEDIO' // Alinhado com o banco ('MEDIO' em vez de 'MEDIUM')
    });

    // Type casting evaluations to avoid model conflict in logic
    const typedEvaluations = evaluations as unknown as DeliveredValueModel[];

    useEffect(() => {
        if (contract?.id) {
            fetchDeliveredValues();
        }
    }, [contract?.id, fetchDeliveredValues]);

    const handleOpenModal = (item?: DeliveredValueModel) => {
        if (item) {
            setItemToEdit(item);
            setFormData({
                delivery_date: item.delivery_date,
                manufacturer_name: item.manufacturer_name || '',
                value_type: item.value_type,
                description: item.description,
                impacted_area: item.impacted_area || 'TI / Tecnologia',
                internal_responsible_id: item.internal_responsible_id || '',
                estimated_impact: item.estimated_impact
            });
        } else {
            setItemToEdit(null);
            setFormData({
                ...formData,
                delivery_date: new Date().toLocaleDateString('en-CA'),
                manufacturer_name: contract?.manufacturer || '',
                description: '',
                internal_responsible_id: currentUser?.id || '',
            });
        }
        setIsModalOpen(true);
    };

    useEffect(() => {
        if (categories.length > 0 && !formData.value_type && !itemToEdit) {
            setFormData(prev => ({ ...prev, value_type: categories[0].key_identifier.toUpperCase() }));
        }
    }, [categories, formData.value_type, itemToEdit]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSubmitting(true);

        const normalizeKey = (val: string) => val?.toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').trim() || '';

        const dataToSave = {
            contract_id: contract.id,
            tenant_id: contract.tenantId, // Garantir tenant_id
            delivery_date: formData.delivery_date,
            manufacturer_name: formData.manufacturer_name || undefined,
            value_type: normalizeKey(formData.value_type),
            description: formData.description,
            impacted_area: formData.impacted_area, // Enviando campo obrigatório
            internal_responsible_id: formData.internal_responsible_id,
            estimated_impact: normalizeKey(formData.estimated_impact),
            created_by: currentUser?.id
        };

        let success = false;
        if (itemToEdit) {
            // No update, removemos campos que não devem mudar ou o Supabase pode reclamar de FK se vierem null
            const { contract_id, tenant_id, created_by, ...updateData } = dataToSave as any;
            success = await updateDeliveredValue(itemToEdit.id, updateData);
        } else {
            success = await addDeliveredValue(dataToSave as any);
        }

        if (success) {
            setIsModalOpen(false);
            setItemToEdit(null);
        }
        setSubmitting(false);
    };

    const handleDeleteClick = (item: DeliveredValueModel) => {
        setItemToDelete(item);
        setIsDeleteModalOpen(true);
    };

    const handleConfirmDelete = async () => {
        if (!itemToDelete) return;
        const success = await deleteDeliveredValue(itemToDelete.id);
        if (success) {
            setIsDeleteModalOpen(false);
            setItemToDelete(null);
        }
    };

    const stats = useMemo(() => {
        const total = typedEvaluations.length;
        const highImpact = typedEvaluations.filter(e => e.estimated_impact === 'HIGH' || e.estimated_impact === 'CRITICAL').length;

        return { total, highImpact };
    }, [typedEvaluations]);

    return (
        <div className="space-y-4">
            {/* Header / Dashboard de Evidências */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white/5 border border-white/10 p-5 rounded-2xl flex flex-col justify-between">
                    <div>
                        <h2 className="text-xl font-bold flex items-center gap-2">
                            <Trophy className="text-primary" />
                            Valor Entregue
                        </h2>
                        <p className="text-sm text-neutral-400 mt-1">
                            Prova de valor e evidências de resultados concretos.
                        </p>
                    </div>
                    <button
                        onClick={() => handleOpenModal()}
                        className="mt-4 flex items-center justify-center gap-2 px-6 py-2.5 bg-gradient-to-r from-primary to-accent hover:to-amber-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-primary/20 hover:shadow-primary/40 transform hover:-translate-y-0.5"
                    >
                        <Plus size={16} strokeWidth={3} /> Registrar Entrega
                    </button>
                </div>

                <div className="bg-neutral-900 border border-neutral-800 p-5 rounded-2xl flex items-center gap-4">
                    <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center text-primary">
                        <Zap size={24} />
                    </div>
                    <div>
                        <span className="text-3xl font-bold block">{stats.total}</span>
                        <span className="text-xs text-neutral-500 uppercase font-semibold">Total de Entregas</span>
                    </div>
                </div>

                <div className="bg-neutral-900 border border-neutral-800 p-5 rounded-2xl flex items-center gap-4">
                    <div className="w-12 h-12 rounded-full bg-orange-500/10 flex items-center justify-center text-orange-500">
                        <Target size={24} />
                    </div>
                    <div>
                        <span className="text-3xl font-bold block">{stats.highImpact}</span>
                        <span className="text-xs text-neutral-500 uppercase font-semibold">Alto Impacto / Crítico</span>
                    </div>
                </div>
            </div>

            {/* Lista de Evidências */}
            <div className="bg-neutral-900 border border-neutral-800 rounded-2xl overflow-hidden">
                <div className="p-4 bg-white/5 border-b border-white/5 flex justify-between items-center">
                    <h3 className="font-semibold flex items-center gap-2 text-neutral-300">
                        <TrendingUp size={18} className="text-primary" />
                        Histórico de Provas de Valor
                    </h3>
                </div>

                {isLoading ? (
                    <div className="p-10 text-center text-neutral-500 animate-pulse">Carregando evidências...</div>
                ) : typedEvaluations.length === 0 ? (
                    <div className="p-10 text-center flex flex-col items-center gap-3">
                        <ShieldCheck size={40} className="text-neutral-700" />
                        <p className="text-neutral-400">Nenhuma evidência de valor registrada neste ciclo.</p>
                        <button
                            className="px-6 py-2.5 bg-gradient-to-r from-primary to-accent hover:to-amber-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-primary/20 hover:shadow-primary/40 transform hover:-translate-y-0.5"
                            onClick={() => handleOpenModal()}
                        >
                            Registrar Primeiro Resultado
                        </button>
                    </div>
                ) : (
                    <div className="divide-y divide-neutral-800">
                        {typedEvaluations.map((item) => (
                            <div key={item.id} className="p-5 hover:bg-white/5 transition-colors">
                                <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                                    <div className="flex-1 space-y-3">
                                        <div className="flex items-center gap-3 flex-wrap">
                                            <span className="text-lg font-bold text-neutral-200">
                                                {format(new Date(`${item.delivery_date}T12:00:00`), "dd/MM/yyyy", { locale: ptBR })}
                                            </span>
