import React, { useState, useEffect } from 'react';
import { Target, PlayCircle } from 'lucide-react';
import { Modal } from '@/components/ui/Modal';
import { CSMStrategy, CSMStrategicObjective, CSMCadenceType } from '@/types/csm';

interface StrategyModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (data: any) => Promise<void>;
    initialData?: CSMStrategy | null;
    objectives: CSMStrategicObjective[];
    cadences: CSMCadenceType[];
    contract: any;
}

export const StrategyModal: React.FC<StrategyModalProps> = ({
    isOpen,
    onClose,
    onSave,
    initialData,
    objectives,
    cadences,
    contract
}) => {
    const [formData, setFormData] = useState({
        objective_name: '',
        cadence_name: '',
        summary: ''
    });
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (initialData) {
            setFormData({
                objective_name: initialData.objective_name,
                cadence_name: initialData.cadence_name,
                summary: initialData.summary || ''
            });
        } else {
            setFormData({
                objective_name: '',
                cadence_name: '',
                summary: ''
            });
        }
    }, [initialData, isOpen]);

    const getSmartSuggestion = () => {
        const objectiveName = formData.objective_name;
        if (!objectiveName) return '';

        const vendor = contract?.manufacturer || 'Fabricante';
        const servicesList = contract?.services?.map((s: any) => s.name).join(', ') || 'serviços atuais';

        switch (objectiveName) {
            case 'MANUTENCAO':
                return `Garantir a estabilidade do contrato de ${vendor}, monitorando a saúde de ${servicesList} para evitar riscos de churn.`;
            case 'EXPANSAO':
                return `Identificar gaps tecnológicos em ${vendor} e propor expansão através de novos serviços que complementem ${servicesList}.`;
            case 'RENOVACAO':
                return `Auditar o valor entregue em ${servicesList} para assegurar uma renovação estratégica e sem objeções.`;
            case 'ESTABILIZACAO':
                return `Acompanhar a performance técnica de ${servicesList} após as mudanças recentes para garantir satisfação total.`;
            case 'ADOCAO':
                return `Fomentar a adoção de novas funcionalidades de ${vendor}, focando em extrair o ROI planejado em ${servicesList}.`;
            default:
                const obj = objectives.find(o => o.name === objectiveName);
                return `Focar em ${obj?.label || 'objetivo estratégico'} para o contrato de ${vendor}, assegurando a entrega de valor em ${servicesList}.`;
        }
    };

    const handleApplySuggestion = () => {
        const suggestion = getSmartSuggestion();
        setFormData({ ...formData, summary: suggestion });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        try {
            await onSave(formData);
            onClose();
        } catch (error) {
            console.error('Error saving strategy:', error);
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <Modal
            isOpen={isOpen}
            onClose={onClose}
            title={initialData ? 'Editar Linha Estratégica' : 'Nova Linha Estratégica'}
            className="max-w-lg"
        >
            <form onSubmit={handleSubmit} className="p-5 space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                        <label className="text-[10px] uppercase font-bold text-neutral-500">Intenção Estratégica</label>
                        <select
                            required
                            value={formData.objective_name}
                            onChange={(e) => setFormData({ ...formData, objective_name: e.target.value })}
                            className="w-full bg-black/40 border border-neutral-800 rounded-lg px-3 py-2 text-sm text-neutral-200 outline-none focus:border-primary/50 transition-all font-bold"
                        >
                            <option value="" disabled>Selecione a intenção...</option>
                            {objectives.filter(o => o.active).map(obj => (
                                <option key={obj.id} value={obj.name}>{obj.label}</option>
                            ))}
                        </select>
                    </div>

                    <div className="space-y-1.5">
                        <label className="text-[10px] uppercase font-bold text-neutral-500">Cadência & Ritmo</label>
                        <select
                            required
                            value={formData.cadence_name}
                            onChange={(e) => setFormData({ ...formData, cadence_name: e.target.value })}
                            className="w-full bg-black/40 border border-neutral-800 rounded-lg px-3 py-2 text-sm text-neutral-200 outline-none focus:border-primary/50 transition-all font-bold"
                        >
                            <option value="" disabled>Selecione a cadência...</option>
                            {cadences
                                .filter(c => c.active)
                                .sort((a, b) => {
                                    const order = ['MENSAL', 'TRIMESTRAL', 'BIMESTRAL', 'on_demand'];
                                    return order.indexOf(a.name) - order.indexOf(b.name);
                                })
                                .map(cad => (
                                    <option key={cad.id} value={cad.name}>{cad.label}</option>
                                ))}
                        </select>
                    </div>
                </div>

                <div className="space-y-1.5">
                    <div className="flex justify-between items-center">
                        <label className="text-[10px] uppercase font-bold text-neutral-500">Resumo Estratégico</label>
                        <button
                            type="button"
                            onClick={handleApplySuggestion}
                            disabled={!formData.objective_name}
                            className="text-[8px] font-black uppercase tracking-widest text-white px-2.5 py-1 bg-gradient-to-r from-primary to-accent hover:to-amber-500 rounded-full transition-all shadow-sm shadow-primary/20 flex items-center gap-1 hover:-translate-y-0.5 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
                        >
                            <PlayCircle size={10} strokeWidth={3} /> Sugestão Inteligente
                        </button>
                    </div>
                    <textarea
                        value={formData.summary}
                        onChange={(e) => setFormData({ ...formData, summary: e.target.value })}
                        placeholder="Descreva a meta principal para esta linha de ação..."
                        rows={4}
                        className="w-full bg-black/40 border border-neutral-800 rounded-lg px-3 py-2 text-sm text-neutral-200 outline-none focus:border-primary/50 transition-all resize-none placeholder:text-neutral-700 font-medium"
                    />
                </div>

                <div className="flex justify-end gap-3 pt-4 border-t border-neutral-800">
                    <button
                        type="button"
                        onClick={onClose}
                        className="px-4 py-2 text-xs font-bold text-neutral-400 hover:text-neutral-200 transition-colors"
                    >
                        Cancelar
                    </button>
                    <button
                        type="submit"
                        disabled={isSaving}
                        className="px-8 py-2.5 bg-gradient-to-r from-primary to-accent hover:to-amber-500 text-white font-black text-xs uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-primary/20 hover:shadow-primary/40 transform hover:-translate-y-0.5 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        {isSaving ? 'Salvando...' : 'Salvar Alterações'}
                    </button>
                </div>
            </form>
        </Modal>
    );
};

