import React, { useState, useRef, useMemo, useEffect } from 'react';
import { FileText, X, AlertTriangle, AlertCircle, Calendar, UploadCloud, Loader2, Trash2, Download, CheckCircle2 } from 'lucide-react';
import { formatCurrency, parseCurrency } from '@/utils/masks';
import { ContractStatus, Periodicity, PaymentStatus, ClientContract, Client, Service, Manufacturer, ContractAddendum, ContractModality, AddendumRecurrence, ContractAttachment } from '@/types/gcc';
import { useContracts } from '@/context/ContractContext';
import { calculateStatus, calculateStatusDetails, calculateRenewalSequence, hasSuccessor } from '@/utils/contractUtils';
import { isAdmin } from '@/utils/permissions';
import { parseISOToDate } from '@/utils/dateUtils';
import { FinalizeConfirmationModal } from '@/components/ui/FinalizeConfirmationModal';
import { AlertModal } from '@/components/ui/AlertModal';
import { contractAddendumService } from '@/modules/gcc/services/ContractAddendumService';
import { storageService } from '@/modules/gcc/services/storageService';
import { useContractLogic } from '@/modules/gcc/hooks/useContractLogic';
import { AddendumList } from './addendums/AddendumList';
import { AddendumForm } from './addendums/AddendumForm';
