// Reusable input style
const inputStyle = "block w-full pl-4 pr-3 py-2 border border-primary/30 hover:border-primary/50 rounded-lg leading-5 bg-black/30 text-neutral-200 placeholder-neutral-600 focus:outline-none focus:bg-black/50 focus:ring-1 focus:ring-primary/50 focus:border-primary sm:text-sm transition-all";

const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
};

interface ContractModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (contract: Partial<ClientContract>) => Promise<{ success: boolean; message?: string; contract?: ClientContract }>;
    clients: Client[];
    services: Service[];
    manufacturers: Manufacturer[];
    contract: ClientContract | null;
}

export const ContractModal: React.FC<ContractModalProps> = ({
    isOpen,
    onClose,
    onSave,
    clients,
    services,
    manufacturers,
    contract
}) => {
    const context = useContracts();
    const contracts = context?.contracts || [];
    const {
        formState,
        setFormState,
        handleChange,
        handleCheckboxChange,
        validateForm,
        errorMessage,
        setErrorMessage,
        isSaving,
        setIsSaving,
        currentUser
    } = useContractLogic(contract, onSave);

    // [MODULAR REPAIR] Status & Permissions Logic
    const { status: currentStatus } = useMemo(() =>
        calculateStatusDetails(formState.expirationDate, formState.id ? formState.status as ContractStatus : undefined),
        [formState.expirationDate, formState.status, formState.id]);

    const isExpired = currentStatus === ContractStatus.Expired;
    const isExpiring = currentStatus === ContractStatus.Expiring;
    const isFinished = formState.status === ContractStatus.Finished;
    const isAdministrator = currentUser?.role === 'Administrador';

    // [LEI 30] Imutabilidade de Finalizados
    // [LEI 48] Janela de Retificação de 30 dias: Apenas Vigente e < 30 dias.
    // [LEI 48 v2.9.9.4] Edição Parcial: Notas editáveis em Vigente/Atenção/Vencendo pós-30 dias.
    const { isEditable, isLegacyActive, canEditOnlyNotes } = useMemo(() => {
        if (isFinished) return { isEditable: false, isLegacyActive: false, canEditOnlyNotes: false };

        // Se for novo contrato, sempre editável
        if (!formState.id) return { isEditable: true, isLegacyActive: false, canEditOnlyNotes: false };

        const isVigente = currentStatus === ContractStatus.Active;
        const isAtencao = currentStatus === ContractStatus.Warning;
        const isVencendo = currentStatus === ContractStatus.Expiring;

        const creationDate = contract?.createdAt ? new Date(contract.createdAt) : new Date();
        const diffDays = Math.floor((Date.now() - creationDate.getTime()) / (1000 * 60 * 60 * 24));
        const isWithinWindow = diffDays <= 30;

        // Regra Base: Edição total permitida se for Admin (histórico) ou se for Vigente e estiver na janela
        const baseEditable = isAdministrator ? (isVigente || isExpired || isAtencao || isVencendo) : (isVigente && isWithinWindow);

        // Edição Parcial de Notas (Lei 48 v2.9.9.4)
        const eligibleForPartial = isVigente || isAtencao || isVencendo;
        const partialOnly = !baseEditable && eligibleForPartial;

        return {
            isEditable: baseEditable,
            isLegacyActive: isVigente && !isWithinWindow,
            canEditOnlyNotes: partialOnly
        };
    }, [isFinished, formState.id, currentStatus, contract?.createdAt, isAdministrator, isExpired, isExpiring]);

    const isRenewing = !!contract && !formState.id;
    const isEditing = !!contract && !!formState.id;

    // Calculate renewal sequence number
    const renewalSequence = useMemo(() => {
        const baseContract = isRenewing ? contract : { ...formState, renewal_base_id: formState.renewal_base_id };
        return calculateRenewalSequence(baseContract as ClientContract, contracts);
    }, [isRenewing, contract, formState.renewal_base_id, contracts]);

    const durations = [12, 24, 36, 48, 60];
    const paymentTerms = ['30 dias', '60 dias', '90 dias', '120 dias'];

    const [dragActive, setDragActive] = useState(false);
    const [fileError, setFileError] = useState<string | null>(null);
    // ErrorMessage handled by hook
    const [isConfirmFinalizeOpen, setIsConfirmFinalizeOpen] = useState(false);
    // isSaving handled by hook
    const [isUploading, setIsUploading] = useState(false);
    const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
    const [attachments, setAttachments] = useState<ContractAttachment[]>(contract?.attachments || []);
    const [removingIds, setRemovingIds] = useState<Set<string>>(new Set());

    // Addendum State
    const [activeTab, setActiveTab] = useState<'details' | 'addendums'>('details');
    const [showAddendumForm, setShowAddendumForm] = useState(false);
    const [addendumRefreshTrigger, setAddendumRefreshTrigger] = useState(0);
    const [editingAddendum, setEditingAddendum] = useState<ContractAddendum | null>(null);
    const [contractAddendums, setContractAddendums] = useState<ContractAddendum[]>([]);
    const [isPeriodicityAlertOpen, setIsPeriodicityAlertOpen] = useState(false);

    // Sync addendums for validation
    useEffect(() => {
        if (contract?.id) {
            contractAddendumService.getAddendums(contract.id).then(setContractAddendums);
        }
    }, [contract?.id, addendumRefreshTrigger]);

    const fileInputRef = useRef<HTMLInputElement>(null);

    const totalSize = useMemo(() => {
        const selectedSize = selectedFiles.reduce((acc, f) => acc + f.size, 0);
        const existingSize = attachments.reduce((acc, a) => acc + (a as any).file_size, 0);
        return selectedSize + existingSize;
    }, [selectedFiles, attachments]);

    const [isSuccess, setIsSuccess] = useState(false);

    if (!isOpen) return null;

    // [MODULAR REPAIR] File Handlers
    const handleDrag = (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        if (e.type === "dragenter" || e.type === "dragover") {
            setDragActive(true);
        } else if (e.type === "dragleave") {
            setDragActive(false);
        }
    };

    const handleDrop = async (e: React.DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        setDragActive(false);
        if (e.dataTransfer.files && e.dataTransfer.files[0]) {
            const files = Array.from(e.dataTransfer.files);
            const validFiles = files.filter(f => f.type === 'application/pdf' || f.name.endsWith('.doc') || f.name.endsWith('.docx'));
            setSelectedFiles(prev => [...prev, ...validFiles].slice(0, 5 - attachments.length));
        }
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const files = Array.from(e.target.files);
            setSelectedFiles(prev => [...prev, ...files].slice(0, 5 - attachments.length));
        }
    };

    const onButtonClick = () => {
        fileInputRef.current?.click();
    };

    const removeAttachment = (att: ContractAttachment) => {
        setAttachments(prev => prev.filter(a => a.id !== att.id));
    };

    const removeSelectedFile = (index: number) => {
        setSelectedFiles(prev => prev.filter((_, i) => i !== index));
    };

    const handleDownload = async (path: string, name: string) => {
        try {
            const url = await storageService.getDownloadUrl(path);
            const link = document.createElement('a');
            link.href = url;
            link.download = name;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        } catch (err) {
            console.error('Download error:', err);
        }
    };

    const handleSave = async () => {
        if (isSaving || isUploading || isSuccess) return;

        if (validateForm()) {
            setIsSaving(true);
            setErrorMessage(null);
            try {
                const saveData = {
                    ...formState,
                    opportunityNumber: formState.opportunityNumber.trim(),
                    dueDay: parseInt(formState.dueDay),
                    monthlyValue: parseCurrency(formState.monthlyValue),
                    value: parseCurrency(formState.value),
                    paymentTermDays: formState.paymentTerm ? parseInt(formState.paymentTerm.match(/\d+/)?.[0] || '0') : 0
                };

                const result = await onSave(saveData as unknown as Partial<ClientContract>);

                if (result.success && result.contract) {
                    const contractId = result.contract.id;
                    const tenantId = result.contract.tenantId || currentUser?.tenantId || '';

                    if (selectedFiles.length > 0) {
                        setIsUploading(true);
                        for (const file of selectedFiles) {
                            try {
                                await storageService.uploadContractFile(contractId, tenantId, file);
                            } catch (err) {
                                console.error('Falha ao subir arquivo:', file.name, err);
                                setErrorMessage(`Falha ao subir arquivo ${file.name}. Verifique as regras de tamanho e quantidade.`);
                                setIsSaving(false);
                                setIsUploading(false);
                                return;
                            }
                        }
                    }

                    // Show success message and close
                    setIsSuccess(true);
                    setTimeout(() => {
                        onClose();
                    }, 1500);

                } else {
                    setIsSaving(false);
                }
            } catch (error) {
                console.error('Contract save error:', error);
                const msg = error instanceof Error ? error.message : "Erro inesperado ao salvar contrato.";
                setErrorMessage(msg);
                setIsSaving(false);
            }
        } else {
            // O setErrorMessage com os detalhes estritos já foi engilhado dentro do validateForm()
            setIsSaving(false);
            const scrollContainer = document.querySelector('.custom-scrollbar');
            if (scrollContainer) scrollContainer.scrollTo({ top: 0, behavior: 'smooth' });
        }
    };

    const handleConfirmFinalization = async () => {
        setFormState(prev => ({ ...prev, status: ContractStatus.Finished }));
        const result = await onSave({ ...formState, status: ContractStatus.Finished } as unknown as Partial<ClientContract>);
        if (result.success) {
            setIsConfirmFinalizeOpen(false);
            setIsSuccess(true);
            setTimeout(() => {
                onClose();
            }, 1500);
        }
    };

    const handleRenewal = () => {
        if (!contract) return;
        console.log('[ContractModal] Iniciando fluxo de renovação para:', contract.id);

        // Helper for safe YYYY-MM-DD parsing handled by parseISOToDate from utils
        const toISODate = (date: Date) => {
            const y = date.getFullYear();
            const m = String(date.getMonth() + 1).padStart(2, '0');
            const d = String(date.getDate()).padStart(2, '0');
            return `${y}-${m}-${d}`;
        };

        // 1. Calculate new start date (day after old expiration)
        const oldExp = parseISOToDate(contract.expirationDate);
        const newStart = new Date(oldExp);
        newStart.setDate(newStart.getDate() + 1);
        const startDateStr = toISODate(newStart);

        // 2. Calculate new expiration date based on periodicity
        const periodicity = formState.periodicity || contract.periodicity;
        // Default to the inherited duration or 12 months as safety
        const duration = parseInt(formState.duration || (contract as any).duration || '12');

        let newExpStr = '';
        const expDate = new Date(newStart);

        if (periodicity === Periodicity.Monthly) {
            expDate.setMonth(expDate.getMonth() + duration);
            newExpStr = toISODate(expDate);
        } else if (periodicity === Periodicity.Annual) {
            expDate.setFullYear(expDate.getFullYear() + 1);
            newExpStr = toISODate(expDate);
        } else if (periodicity === Periodicity.Biennial) {
            expDate.setFullYear(expDate.getFullYear() + 2);
            newExpStr = toISODate(expDate);
        } else if (periodicity === Periodicity.Triennial) {
            expDate.setFullYear(expDate.getFullYear() + 3);
            newExpStr = toISODate(expDate);
        } else {
            // Generic fallback: +1 year if no periodicity match
            expDate.setFullYear(expDate.getFullYear() + 1);
            newExpStr = toISODate(expDate);
        }

        // 3. Prepare transition state
        setFormState(prev => ({
            ...prev,
            id: undefined, // Treat as new record
            renewal_base_id: contract.id,
            opportunityNumber: '', // Reset for new negotiation
            startDate: startDateStr,
            expirationDate: newExpStr,
            // Explicit Inheritance (Rule 4)
            manufacturerId: contract.manufacturerId || '',
            serviceIds: contract.serviceIds || [],
            status: '' // Let it be calculated
        }));

        setErrorMessage(null);
    };

    const handleInitialConclude = () => {
        if (contract?.installments && contract.installments.length > 0) {
            const hasUnpaid = contract.installments.some(inst => inst.status !== 'Pago');
            if (hasUnpaid) {
                setErrorMessage("Não é possível finalizar o contrato: existem parcelas pendentes.");
                const scrollContainer = document.querySelector('.custom-scrollbar');
                if (scrollContainer) scrollContainer.scrollTo({ top: 0, behavior: 'smooth' });
                return;
            }
        }
        setIsConfirmFinalizeOpen(true);
    };

    const handleClose = () => {
        if (isSaving || isUploading || isSuccess) return;
        onClose();
    };

    // Success View
    if (isSuccess) {
        return (
            <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 animate-fade-in p-4">
                <div className="bg-surface border border-emerald-500/30 rounded-xl shadow-2xl p-8 flex flex-col items-center justify-center max-w-sm w-full animate-scale-in">
                    <div className="w-16 h-16 bg-emerald-500/10 rounded-full flex items-center justify-center mb-4 text-emerald-500">
                        <CheckCircle2 size={32} />
                    </div>
                    <h2 className="text-xl font-bold text-white mb-2">Contrato Salvo!</h2>
                    <p className="text-neutral-400 text-center text-sm">
                        As parcelas foram recalculadas e as alterações salvas com sucesso.
                    </p>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 animate-fade-in p-4" onClick={handleClose} >
            <div
                className="bg-surface border border-neutral-800 rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col max-h-[90vh]"
                onClick={e => e.stopPropagation()}
            >
                {/* Header */}
                <div className="px-8 py-6 border-b border-neutral-800 flex justify-between items-center bg-black/20">
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-lg bg-primary/10 text-primary">
                            <FileText size={20} />
                        </div>
                        <h2 className="text-xl font-bold text-neutral-100">
                            {isRenewing ? 'Renovar Contrato' : (isEditing ? 'Editar Contrato' : 'Novo Contrato')}
                        </h2>
                    </div>
                    {(isExpired || isExpiring) && (
                        <div className="mx-auto flex gap-2">
                            {formState.renewal_base_id && (
                                <div className="bg-amber-500/10 border border-amber-500/20 px-3 py-1 rounded text-amber-500 text-[10px] font-bold flex items-center gap-2 shadow-[0_0_10px_rgba(245,158,11,0.1)]">
                                    <CheckCircle2 size={13} />
                                    {renewalSequence}ª Renovação
                                </div>
                            )}
                            {isExpired ? (
                                <div className="bg-red-500/10 border border-red-500/20 px-3 py-1 rounded text-red-400 text-xs font-medium flex items-center gap-2">
                                    <AlertTriangle size={14} />
                                    Vencido
                                </div>
                            ) : (
                                <div className="bg-amber-500/10 border border-amber-500/20 px-3 py-1 rounded text-amber-400 text-xs font-medium flex items-center gap-2">
                                    <AlertTriangle size={14} />
                                    Vencendo
                                </div>
                            )}
                        </div>
                    )}
                    {isFinished && (
                        <div className="mx-auto bg-sky-500/10 border border-sky-500/20 px-3 py-1 rounded text-sky-400 text-xs font-medium flex items-center gap-2">
                            <AlertCircle size={14} />
                            Finalizado
                        </div>
                    )}
                    <button
                        type="button"
                        onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            handleClose();
                        }}
                        className="text-neutral-500 hover:text-neutral-300 transition-colors"
                        disabled={isSaving || isUploading}
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Content */}
                <div className="flex border-b border-neutral-800 px-8">
                    <button
                        type="button"
                        onClick={() => setActiveTab('details')}
                        className={`px-4 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'details' ? 'border-primary text-primary' : 'border-transparent text-neutral-400 hover:text-neutral-200'}`}
                    >
                        Detalhes do Contrato
                    </button>
                    {isEditing && !isRenewing && (
                        <button
                            type="button"
                            onClick={() => setActiveTab('addendums')}
                            className={`px-4 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'addendums' ? 'border-primary text-primary' : 'border-transparent text-neutral-400 hover:text-neutral-200'}`}
                        >
                            Aditivos e Eventos
                        </button>
                    )}
                </div>

                <div className="p-8 overflow-y-auto custom-scrollbar flex-1 space-y-6">
                    {activeTab === 'addendums' && isEditing && contract ? (
                        <div className="animate-fade-in space-y-6">
                            <div className="flex justify-between items-center">
                                <div>
                                    <h3 className="text-lg font-bold text-neutral-100">Histórico de Aditivos</h3>
                                    <p className="text-xs text-neutral-500">Registre alterações de valor e escopo neste contrato.</p>
                                </div>
                                {!showAddendumForm && isEditable && (
                                    <button
                                        type="button"
                                        onClick={() => {
                                            setEditingAddendum(null);
                                            setShowAddendumForm(true);
                                        }}
                                        className="px-3 py-1.5 bg-primary/10 border border-primary/20 text-primary rounded text-xs font-bold hover:bg-primary/20 transition-all flex items-center gap-2"
                                    >
                                        + Novo Aditivo
                                    </button>
                                )}
                            </div>

                            {showAddendumForm ? (
                                <AddendumForm
                                    contractId={contract.id}
                                    contractServices={services.filter(s => contract.serviceIds.map(String).includes(String(s.id)))}
                                    contractStartDate={formState.startDate}
                                    contractExpirationDate={formState.expirationDate}
                                    contractPeriodicity={formState.periodicity as any}
                                    initialData={editingAddendum || undefined}
                                    onSuccess={() => {
                                        setShowAddendumForm(false);
                                        setEditingAddendum(null);
                                        setAddendumRefreshTrigger(prev => prev + 1);
                                        // Trigger parent refresh if needed, usually passed via props or context.
                                        // For now, modal remains open and list refreshes.
                                    }}
                                    onCancel={() => {
                                        setShowAddendumForm(false);
                                        setEditingAddendum(null);
                                    }}
                                />
                            ) : (
                                <AddendumList
                                    contractId={contract.id}
                                    refreshTrigger={addendumRefreshTrigger}
                                    onEdit={(addendum) => {
                                        setEditingAddendum(addendum);
                                        setShowAddendumForm(true);
                                    }}
                                    isEditable={isEditable}
                                />
                            )}
                        </div>
                    ) : (
                        <form id="contract-form" onSubmit={(e) => { e.preventDefault(); handleSave(); }} className="space-y-4">
                            {errorMessage && (
                                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-lg flex items-center gap-3 text-red-500 animate-slide-in">
                                    <AlertCircle size={20} />
                                    <p className="text-sm font-medium">{errorMessage}</p>
                                </div>
                            )}

                            {isExpired && !isAdministrator && isEditing && (
                                <div className="p-4 bg-red-500/10 border border-red-500/20 rounded-lg flex items-center gap-3 text-red-500 animate-slide-in">
                                    <AlertTriangle size={20} />
                                    <p className="text-sm font-medium">Este contrato está vencido. Apenas administradores podem realizar edições históricas.</p>
                                </div>
                            )}

                            <section>
                                <div className="flex items-center justify-between mb-4">
                                    <div className="flex items-center gap-2">
                                        <div className="w-1.5 h-6 bg-primary rounded-full" />
                                        <h3 className="text-sm font-bold text-white uppercase tracking-widest">Informações Gerais</h3>
                                    </div>
                                    {isEditable && isEditing && !isAdministrator && (
                                        <span className="text-[10px] text-neutral-500 font-medium italic">
                                            Janela de retificação inicial de 30 dias ativa (Lei 48)
                                        </span>
                                    )}
                                </div>
                                <ContractGeneralTab
                                    formState={formState}
                                    setFormState={setFormState}
                                    handleChange={handleChange}
                                    isEditable={isEditable}
                                    canEditOnlyNotes={canEditOnlyNotes}
                                    clients={clients}
                                    manufacturers={manufacturers}
                                    services={services}
                                    inputStyle={inputStyle}
                                />
                            </section>

                            <section>
                                <div className="flex items-center gap-2 mb-4">
                                    <div className="w-1.5 h-6 bg-accent rounded-full" />
                                    <h3 className="text-sm font-bold text-white uppercase tracking-widest">Vigência e Financeiro</h3>
                                </div>
                                <ContractFinancialsTab
                                    formState={formState}
                                    handleChange={handleChange}
                                    handleCheckboxChange={handleCheckboxChange}
                                    isEditable={isEditable}
                                    isRenewing={isRenewing}
                                    isEditing={isEditing}
                                    contract={contract}
                                    contractAddendums={contractAddendums}
                                    setIsPeriodicityAlertOpen={setIsPeriodicityAlertOpen}
                                    currentStatus={currentStatus}
                                    inputStyle={inputStyle}
                                />
                            </section>

                            <section>
                                <div className="flex items-center gap-2 mb-4">
                                    <div className="w-1.5 h-6 bg-neutral-600 rounded-full" />
                                    <h3 className="text-sm font-bold text-white uppercase tracking-widest">Documentos</h3>
                                </div>
                                <ContractAttachmentsTab
                                    attachments={attachments}
                                    selectedFiles={selectedFiles}
                                    isEditable={isEditable}
                                    isUploading={isUploading}
                                    totalSize={totalSize}
                                    dragActive={dragActive}
                                    handleDrag={handleDrag}
                                    handleDrop={handleDrop}
                                    onButtonClick={onButtonClick}
                                    fileInputRef={fileInputRef}
                                    handleFileChange={handleFileChange}
                                    fileError={fileError}
                                    removeAttachment={removeAttachment}
                                    removeSelectedFile={removeSelectedFile}
                                    handleDownload={handleDownload}
                                    formatFileSize={formatFileSize}
                                    removingIds={removingIds}
                                />
                            </section>
                        </form>
                    )}
                </div>

                <div className="px-8 py-6 border-t border-neutral-800 bg-neutral-900/50 flex justify-end gap-3">
                    {activeTab === 'details' && (
                        <>
                            <button type="button" onClick={handleClose} disabled={isSaving || isUploading} className="px-6 py-2.5 bg-neutral-800 border border-neutral-700 rounded-lg text-sm font-medium text-neutral-300 hover:text-white transition-all disabled:opacity-50">
                                Cancelar
                            </button>
                            {contract && (isExpired || isExpiring) && !isRenewing && !hasSuccessor(contract.id, contracts) && (
                                <div className="flex gap-3">
                                    <button
                                        type="button"
                                        onClick={handleRenewal}
                                        disabled={isSaving}
                                        className="px-6 py-2.5 bg-neutral-800 border border-neutral-700 text-primary font-bold rounded-lg text-sm hover:bg-primary/10 transition-all flex items-center gap-2 group"
                                    >
                                        <CheckCircle2 size={16} className="group-hover:scale-110 transition-transform" />
                                        Renovar Contrato
                                    </button>
                                    <button
                                        type="button"
                                        onClick={handleInitialConclude}
                                        disabled={isSaving}
                                        className="px-8 py-2.5 bg-sky-600 hover:bg-sky-500 text-white font-bold rounded-lg text-sm transition-all shadow-lg flex items-center gap-2"
                                    >
                                        {isSaving ? <Loader2 size={16} className="animate-spin" /> : null}
                                        Concluir Contrato
                                    </button>
                                </div>
                            )}
                            {(isEditable || canEditOnlyNotes) && (
                                <button type="submit" form="contract-form" disabled={isSaving || isUploading} className="px-8 py-2.5 bg-gradient-to-r from-primary to-accent hover:to-amber-500 text-white font-bold rounded-lg text-sm transition-all shadow-lg disabled:opacity-50 flex items-center justify-center gap-2">
                                    {isSaving || isUploading ? (
                                        <>
                                            <Loader2 size={16} className="animate-spin" />
                                            {isUploading ? 'Subindo arquivos...' : 'Salvando...'}
                                        </>
                                    ) : (
                                        contract ? 'Salvar Contrato' : 'Cadastrar Contrato'
                                    )}
                                </button>
                            )}
                        </>
                    )}
                    {activeTab === 'addendums' && (
                        <button type="button" onClick={handleClose} className="px-6 py-2.5 bg-neutral-800 border border-neutral-700 rounded-lg text-sm font-medium text-neutral-300 hover:text-white transition-all">
                            Fechar
                        </button>
                    )}
                </div>
            </div >

            <AlertModal
                isOpen={isPeriodicityAlertOpen}
                onClose={() => setIsPeriodicityAlertOpen(false)}
                title="Bloqueio de Estrutura"
                description="Não é possível alterar a periodicidade de Mensal para Anual/Bienal/Trienal enquanto existam aditivos de recorrência mensal ativos. Por favor, remova ou converta os aditivos mensais antes de alterar a estrutura do contrato."
                type="error"
            />

            <FinalizeConfirmationModal
                isOpen={isConfirmFinalizeOpen}
                onClose={() => setIsConfirmFinalizeOpen(false)}
                onConfirm={handleConfirmFinalization}
                itemIdentifier={contract ? `${contract.service} - ${contract.clientName}` : undefined}
                isSaving={isSaving}
            />
        </div >
    );
};

